\begin{definition}
[Push--pull functor]
  \label{def:push_pull_functor}
  \lean{AlgebraicGeometry.pushPullFunctor}
  \uses{def:push_pull_obj, def:push_pull_map, lem:push_pull_id, lem:push_pull_comp}
  The \emph{push--pull functor}
  \[
    G : (X/\mathbf{Sch})^{\mathrm{op}} \longrightarrow \operatorname{QCoh}(X),
  \]
  assembling the object map \(p \mapsto p_*\, p^*\mathcal{F}\) of
  Definition~\ref{def:push_pull_obj} and the comparison morphism map of
  Definition~\ref{def:push_pull_map} into a genuine functor. Functoriality is exactly the two
  laws established above: the identity law
  Lemma~\ref{lem:push_pull_id} and the composition law Lemma~\ref{lem:push_pull_comp}. The
  functor is contravariant in the over-category \((X/\mathbf{Sch})\); it is the lift of the
  geometric backbone (1) to \(\mathcal{O}_X\)-modules described as step (2) above.
\end{definition}

\begin{definition}
[{\v C}ech nerve cosimplicial object]
  \label{def:cech_nerve_cosimplicial}
  \lean{AlgebraicGeometry.cechNerveCosimplicial}
  \uses{def:cover_cech_nerve, def:push_pull_functor}
  The (non-augmented) cosimplicial \(\mathcal{O}_X\)-module obtained by transporting the
  geometric {\v C}ech backbone in \((X/\mathbf{Sch})\) of
  Definition~\ref{def:cover_cech_nerve} through the push--pull functor
  \(G\) of Definition~\ref{def:push_pull_functor}: degreewise, the \(p\)-th term is the
  product over \((i_0, \ldots, i_p) \in I^{p+1}\) of the \((p+1)\)-fold-intersection
  pushforwards \((j_{i_0 \ldots i_p})_*(\mathcal{F}|_{U_{i_0 \ldots i_p}})\). This is the
  underlying cosimplicial object that the {\v C}ech nerve of
  Definition~\ref{def:cech_nerve} augments by the structure map \(\mathcal{F} \to
  \mathcal{C}^0\).
\end{definition}

